use std::collections::HashMap;
use std::sync::{Arc, Mutex, RwLock};

#[derive(Clone, Debug)]
pub struct Inventory {
    stock: Arc<RwLock<HashMap<String, Arc<Mutex<u32>>>>>,
}

impl Inventory {
    pub fn new(initial_stock: HashMap<String, u32>) -> Self {
        let stock = initial_stock
            .into_iter()
            .map(|(item, qty)| (item, Arc::new(Mutex::new(qty))))
            .collect();

        Self {
            stock: Arc::new(RwLock::new(stock)),
        }
    }

    pub fn get_stock(&self, item: &str) -> Option<u32> {
        let stock_map = self.stock.read().ok()?;
        let item_lock = stock_map.get(item)?.clone();
        drop(stock_map);

        let qty = item_lock.lock().ok()?;
        Some(*qty)
    }

    pub fn decrement_stock(&self, item: &str, amount: u32) -> Result<u32, String> {
        let stock_map = self
            .stock
            .read()
            .map_err(|_| "inventory lock poisoned".to_string())?;

        let item_lock = stock_map
            .get(item)
            .cloned()
            .ok_or_else(|| format!("item '{}' not found", item))?;

        drop(stock_map);

        let mut qty = item_lock
            .lock()
            .map_err(|_| format!("item '{}' lock poisoned", item))?;

        if *qty < amount {
            return Err(format!(
                "insufficient stock for '{}': requested {}, available {}",
                item, amount, *qty
            ));
        }

        *qty -= amount;
        Ok(*qty)
    }

    pub fn restock(&self, item: &str, amount: u32) -> Result<u32, String> {
        let stock_map = self
            .stock
            .read()
            .map_err(|_| "inventory lock poisoned".to_string())?;

        let item_lock = stock_map
            .get(item)
            .cloned()
            .ok_or_else(|| format!("item '{}' not found", item))?;

        drop(stock_map);

        let mut qty = item_lock
            .lock()
            .map_err(|_| format!("item '{}' lock poisoned", item))?;

        *qty += amount;
        Ok(*qty)
    }

    pub fn add_item(&self, item: String, quantity: u32) -> Result<(), String> {
        let mut stock_map = self
            .stock
            .write()
            .map_err(|_| "inventory lock poisoned".to_string())?;

        if stock_map.contains_key(&item) {
            return Err(format!("item '{}' already exists", item));
        }

        stock_map.insert(item, Arc::new(Mutex::new(quantity)));
        Ok(())
    }
}

pub fn handle_concurrent_inventory_updates() {
    use std::thread;

    let mut initial = HashMap::new();
    initial.insert("laptop".to_string(), 10);
    initial.insert("mouse".to_string(), 25);

    let inventory = Arc::new(Inventory::new(initial));

    let mut handles = Vec::new();

    for _ in 0..8 {
        let inv = Arc::clone(&inventory);
        handles.push(thread::spawn(move || {
            let _ = inv.get_stock("laptop");
            let _ = inv.decrement_stock("laptop", 1);
        }));
    }

    for _ in 0..5 {
        let inv = Arc::clone(&inventory);
        handles.push(thread::spawn(move || {
            let _ = inv.get_stock("mouse");
            let _ = inv.decrement_stock("mouse", 2);
        }));
    }

    for handle in handles {
        let _ = handle.join();
    }

    let laptop_remaining = inventory.get_stock("laptop").unwrap_or(0);
    let mouse_remaining = inventory.get_stock("mouse").unwrap_or(0);

    println!("Remaining laptop stock: {}", laptop_remaining);
    println!("Remaining mouse stock: {}", mouse_remaining);
}